/* ════════════════════════════════════════════════════════════════════
 * P01 Storage Guard — prevents partial saves, enforces module ownership
 * Módulos: 'edital', 'leitura', 'concursos', 'ST'
 * ════════════════════════════════════════════════════════════════════ */
const P01Storage = (function() {
  'use strict';

  // ── Safe save: always reads existing data first, merges, then writes ──
  function safeSave(key, newData) {
    try {
      const existing = safeLoad(key) || {};
      const merged = Object.assign({}, existing, newData);
      localStorage.setItem(key, JSON.stringify(merged));
      return true;
    } catch(e) {
      console.warn('[P01Storage] safeSave failed for key:', key, e.message);
      return false;
    }
  }

  // ── Safe load: returns null on parse error, never throws ──────────────
  function safeLoad(key) {
    try {
      const raw = localStorage.getItem(key);
      return raw ? JSON.parse(raw) : null;
    } catch(e) {
      console.warn('[P01Storage] safeLoad parse error for key:', key, e.message);
      return null;
    }
  }

  // ── Safe remove: won't throw ──────────────────────────────────────────
  function safeRemove(key) {
    try { localStorage.removeItem(key); return true; }
    catch(e) { return false; }
  }

  // ── Validate data has expected fields ─────────────────────────────────
  function validate(data, requiredFields) {
    if (!data || typeof data !== 'object') return false;
    return requiredFields.every(function(f) { return f in data; });
  }

  return { safeSave, safeLoad, safeRemove, validate };
})();


/* ════════════════════════════════════════════════════════════════════
 * P01 Module Lifecycle Standard
 * ────────────────────────────────────────────────────────────────────
 * Every V2 module MUST implement:
 *
 *   build()   — creates DOM shell, called once on first tab open
 *   render()  — updates DOM with current state, called on every refresh
 *   teardown()— optional, called when concurso changes or tab closes
 *   rebuild() — teardown + build + render (used by _reconstruirUI)
 *
 * Pattern (copy this for new V2 modules):
 *
 *   const MODULE = (function(){
 *     const STATE = { ... };
 *
 *     function build(){ ... }    // creates #module-root innerHTML
 *     function render(){ ... }   // updates data in existing DOM
 *     function teardown(){ STATE.active = null; }
 *     function rebuild(){ teardown(); build(); render(); }
 *
 *     // goTab hook (safe pattern):
 *     document.addEventListener('DOMContentLoaded', function(){
 *       const _orig = window.goTab;
 *       window.goTab = function(id){
 *         _orig(id);
 *         if(id === 'MODULE_TAB_ID'){
 *           try{
 *             if(document.getElementById('module-root')) render();
 *             else setTimeout(build, 30);
 *           } catch(e){ console.warn('[MODULE] goTab error:', e.message); }
 *         }
 *       };
 *       // concTrocar hook (safe pattern):
 *       const _origConc = window.concTrocar;
 *       window.concTrocar = function(id){
 *         _origConc(id);
 *         const tab = document.getElementById('tab-MODULE');
 *         if(tab && tab.classList.contains('active')){
 *           teardown(); setTimeout(build, 80);
 *         }
 *       };
 *     });
 *   })();
 *
 * CSS Rule (mandatory):
 *   #tab-MODULE {
 *     --mod-*: tokens only, NEVER display:block or min-height
 *   }
 *   #tab-MODULE.active { min-height: calc(100vh - 44px); }
 *
 * Storage Rule (mandatory):
 *   Always save: { primaryData, auxiliaryData } together
 *   Never save only one field — this causes partial overwrites.
 * ════════════════════════════════════════════════════════════════════ */

const P01Lifecycle = {
  // Registry of active V2 modules
  _modules: {},

  register: function(name, obj) {
    if (!obj.build || !obj.render) {
      console.warn('[P01Lifecycle] Module "'+name+'" missing build() or render()');
      return;
    }
    this._modules[name] = obj;
  },

  // Safe rebuild for _reconstruirUI
  rebuildAll: function() {
    Object.keys(this._modules).forEach(function(name) {
      var mod = P01Lifecycle._modules[name];
      try {
        if (typeof mod.teardown === 'function') mod.teardown();
        if (typeof mod.rebuild === 'function') mod.rebuild();
        else { mod.build(); mod.render(); }
      } catch(e) {
        console.warn('[P01Lifecycle] rebuildAll failed for "'+name+'":', e.message);
      }
    });
  }
};


/* ════════════════════════════════════════════════════════════════════
 * P01 Engineering Guards — Runtime integrity checks
 * Runs on DOMContentLoaded, reports issues to console only.
 * Never throws, never blocks UI.
 * ════════════════════════════════════════════════════════════════════ */
(function P01Guard() {
  'use strict';

  function run() {
    var issues = [];

    // ── 1. Duplicate ID check ───────────────────────────────────────
    var allIds = {};
    document.querySelectorAll('[id]').forEach(function(el) {
      var id = el.id;
      if (allIds[id]) {
        issues.push('DUPLICATE_ID: #' + id);
      }
      allIds[id] = true;
    });

    // ── 2. TABS_LIST vs DOM check ───────────────────────────────────
    var TABS = typeof TABS_LIST !== 'undefined' ? TABS_LIST : [];
    TABS.forEach(function(tabId) {
      if (!document.getElementById('tab-' + tabId)) {
        issues.push('MISSING_TAB: tab-' + tabId + ' not in DOM');
      }
    });

    // ── 3. Section visibility sanity check ─────────────────────────
    var activeSections = document.querySelectorAll('.section.active');
    if (activeSections.length === 0) {
      issues.push('NO_ACTIVE_SECTION: no section has .active class');
    }
    if (activeSections.length > 1) {
      var ids = Array.from(activeSections).map(function(s){ return '#'+s.id; });
      issues.push('MULTIPLE_ACTIVE_SECTIONS: ' + ids.join(', '));
    }

    // ── 4. Storage accessibility ────────────────────────────────────
    try {
      localStorage.setItem('p01_guard_test', '1');
      localStorage.removeItem('p01_guard_test');
    } catch(e) {
      issues.push('LOCALSTORAGE_UNAVAILABLE: ' + e.message);
    }

    // ── Report ──────────────────────────────────────────────────────
    if (issues.length === 0) {
      console.log('[P01Guard] ✓ All integrity checks passed');
    } else {
      console.group('[P01Guard] ⚠️  ' + issues.length + ' issue(s) found:');
      issues.forEach(function(i){ console.warn('  ' + i); });
      console.groupEnd();
    }

    return issues;
  }

  // Expose for manual re-run: P01Guard() in console
  window.P01Guard = run;

  document.addEventListener('DOMContentLoaded', function() {
    // Run after all modules initialize (slight delay)
    setTimeout(run, 500);
  });
})();
